// ---------- 한글 조사 ----------
function hasJong(w){ if(!w) return false; const c=w.charCodeAt(w.length-1); if(c>=0xAC00&&c<=0xD7A3) return (c-0xAC00)%28!==0; return false; }
function J(w,a,b){ return w+(hasJong(w)?a:b); }

