// ---------- 페이지: 동+과목+대상 ----------
function pageSubject(dong, subj, lv, chere){
  const g = LG[lv], kw = `${dong} ${lv}${subj}학원`, kws = `${dong} ${subj}학원`;
  const sgg = chere[0].sgg;
  const paras = genBody(dong, subj, lv, chere);
  const lead = paras[0];
  const secs = paras.slice(1).map(p=>{
    if(p.startsWith("■")){ const [h,...rest]=p.split("\n"); return `<div class="sec"><h2>${esc(h.replace("■ ",""))}</h2><p>${esc(rest.join("\n"))}</p></div>`; }
    return `<div class="sec"><p>${esc(p)}</p></div>`;
  }).join("");
  const cards = chere.map(c=>centerCard(c,lv)).join("");
  const canonical = `${SITE_URL}/${enc(dong)}-${enc(lv)}${enc(subj)}학원`;
  const desc = `${sgg} ${dong} ${g} ${subj} 학원 정보. 인근 학교 내신 대비와 ${subj} 학습 관리 안내. 자세한 사항은 방문상담으로 확인하세요.`;
  const jsonld = JSON.stringify({"@context":"https://schema.org","@type":"FAQPage","mainEntity":[{"@type":"Question","name":`${dong}에서 ${g} ${subj}를 처음 시작해도 괜찮을까요?`,"acceptedAnswer":{"@type":"Answer","text":"학생의 현재 수준을 먼저 진단한 뒤 그에 맞는 단계부터 시작하기 때문에, 기초가 부족한 학생도 자신의 속도에 맞춰 학습할 수 있습니다."}},{"@type":"Question","name":"수업 시간과 교습비는 어떻게 되나요?","acceptedAnswer":{"@type":"Answer","text":"수업 시간과 교습비는 지역별·과목별로 다를 수 있으며, 자세한 사항은 방문상담을 통해 안내받으실 수 있습니다."}}]});
  const related = relatedChips(dong, subj, lv);
  const body = `
<div class="bc"><a href="/">홈</a> › <a href="/${enc(dong)}">${esc(dong)}</a> › ${esc(kw)}</div>
<h1>${esc(kw)}</h1>
<p class="lead">${esc(lead)}</p>
${secs}
<div class="sec"><h2>${esc(dong)} ${esc(subj)} 학원 안내</h2></div>
<div class="cards">${cards}</div>
${related}
<div class="note">정확한 수업 시간 및 교습비는 지역별·과목별로 상이할 수 있습니다. 자세한 사항은 각 학원에 방문상담을 통해 확인하시기 바랍니다.</div>`;
  return layout({title:`${kw} | ${sgg} ${subj} 학원 정보`, desc, canonical, jsonld, body});
}

function centerCard(c, lv){
  const sj = Object.keys(c.subj||{}).map(s=>`<span class="tag">${esc(s)}</span>`).join("");
  const sch = (schoolsFor(c,lv)||[]).slice(0,6).join(", ");
  return `<div class="card">
<h3><a href="/center/${c.id}" style="color:inherit;text-decoration:none">${esc(c.dong)} 학원</a></h3>
<div class="meta">📍 ${esc(c.addr)}</div>
${sch?`<div class="meta">🏫 인근 학교: ${esc(sch)}</div>`:""}
<div style="margin-top:8px">${sj}</div>
<div class="reg">${esc(c.name)} · ${esc(c.office)}</div>
</div>`;
}

function relatedChips(dong, subj, lv){
  const idx = buildIndex();
  const chips = [];
  // 같은 동 다른 과목
  SUBJECTS.forEach(s=>{ if(s!==subj){ const k=`${dong}|${s}|${lv}`; if(idx.pages[k]) chips.push(`<a class="chip" href="/${enc(dong)}-${enc(lv)}${enc(s)}학원">${esc(dong)} ${esc(LG[lv])} ${esc(s)}</a>`); }});
  // 같은 동 같은 과목 다른 대상
  LEVELS.forEach(l=>{ if(l!==lv){ const k=`${dong}|${subj}|${l}`; if(idx.pages[k]) chips.push(`<a class="chip" href="/${enc(dong)}-${enc(l)}${enc(subj)}학원">${esc(dong)} ${esc(LG[l])} ${esc(subj)}</a>`); }});
  if(!chips.length) return "";
  return `<div class="sec"><h2>이런 정보도 함께 보세요</h2><div class="chips">${chips.join("")}</div></div>`;
}

// ---------- 페이지: 동 ----------
function pageDong(dong, chere){
  const idx = buildIndex();
  const sgg = chere[0].sgg;
  const combos = {};
  Object.keys(idx.pages).forEach(k=>{ const [d,s,l]=k.split("|"); if(d===dong){ combos[`${l}|${s}`]=true; } });
  const chipHtml = Object.keys(combos).sort().map(c=>{ const [l,s]=c.split("|"); return `<a class="chip" href="/${enc(dong)}-${enc(l)}${enc(s)}학원">${esc(dong)} ${esc(LG[l])} ${esc(s)}</a>`; }).join("");
  const cards = chere.map(c=>centerCard(c,"중등")).join("");
  const canonical = `${SITE_URL}/${enc(dong)}`;
  const desc = `${sgg} ${dong} 학원 정보. ${dong} 지역 과목별·학년별 학원 안내와 인근 학교 내신 대비 정보를 확인하세요.`;
  const body = `
<div class="bc"><a href="/">홈</a> › ${esc(dong)}</div>
<h1>${esc(dong)} 학원 정보</h1>
<p class="lead">${esc(sgg)} ${esc(dong)} 지역의 과목별·학년별 학원 정보를 안내합니다. 아래에서 원하는 과목과 학년을 선택해 자세한 내용을 확인하세요.</p>
<div class="sec"><h2>${esc(dong)} 과목·학년별 학원</h2><div class="chips">${chipHtml}</div></div>
<div class="sec"><h2>${esc(dong)} 학원 목록</h2></div>
<div class="cards">${cards}</div>
<div class="note">정확한 수업 시간 및 교습비는 각 학원에 방문상담을 통해 확인하시기 바랍니다.</div>`;
  return layout({title:`${dong} 학원 | ${sgg} 과목별 학원 정보`, desc, canonical, jsonld:"", body});
}

// ---------- 페이지: 센터 상세 ----------
function pageCenter(c){
  const subjList = Object.keys(c.subj||{});
  const rows = subjList.map(s=>`<div class="meta">📘 ${esc(s)}: ${esc((c.subj[s]||[]).map(l=>LG[l]).join(", "))}</div>`).join("");
  const schoolBlk = [["초등학교",c.e],["중학교",c.m],["고등학교",c.h]].filter(x=>x[1]&&x[1].length).map(x=>`<div class="meta">🏫 ${x[0]}: ${esc(x[1].join(", "))}</div>`).join("");
  const canonical = `${SITE_URL}/center/${c.id}`;
  const desc = `${c.sgg} ${c.dong} 학원 정보. 과목별 가능 학년과 인근 학교 안내. ${c.office}`;
  const jsonld = JSON.stringify({"@context":"https://schema.org","@type":"EducationalOrganization","name":c.name,"address":{"@type":"PostalAddress","streetAddress":c.addr,"addressCountry":"KR"},"areaServed":c.dong});
  const body = `
<div class="bc"><a href="/">홈</a> › <a href="/${enc(c.dong)}">${esc(c.dong)}</a> › 학원 안내</div>
<h1>${esc(c.dong)} 학원</h1>
<p class="lead">${esc(c.sgg)} ${esc(c.dong)}에 위치한 학원 정보입니다. 과목별 가능 학년과 인근 학교 정보를 안내합니다.</p>
<div class="card">
<h3>학원 정보</h3>
<div class="meta">📍 주소: ${esc(c.addr)}</div>
${c.open?`<div class="meta">🕒 운영: ${esc(c.open)}</div>`:""}
${c.wk?`<div class="meta">📅 주말 수업: ${esc(c.wk)}</div>`:""}
</div>
<div class="card"><h3>지도 가능 과목·학년</h3>${rows}</div>
${schoolBlk?`<div class="card"><h3>인근 학교</h3>${schoolBlk}</div>`:""}
<div class="card"><h3>학원 등록 정보</h3>
<div class="meta">정식 명칭: ${esc(c.name)}</div>
<div class="meta">${esc(c.office)}</div>
</div>
<div class="note">상담은 예약제로 운영될 수 있습니다. 정확한 수업 시간 및 교습비는 방문상담을 통해 확인하시기 바랍니다.</div>`;
  return layout({title:`${c.dong} 학원 | ${c.sgg} 학원 정보`, desc, canonical, jsonld, body});
}

// ---------- 페이지: 메인 ----------
function pageHome(){
  const idx = buildIndex();
  const dongs = Object.values(idx.dongList);
  const bySgg = {};
  dongs.forEach(d=>{ (bySgg[d.sgg]=bySgg[d.sgg]||[]).push(d.dong); });
  const sggKeys = Object.keys(bySgg).sort();
  const grid = sggKeys.slice(0,60).map(sgg=>{
    const ds = [...new Set(bySgg[sgg])].sort();
    return ds.map(d=>`<a href="/${enc(d)}">${esc(d)}<small>${esc(sgg)}</small></a>`).join("");
  }).join("");
  const canonical = SITE_URL+"/";
  const body = `
<div class="hero"><h1>우리 동네 학원 정보, 세모학원찾기</h1>
<p>전국 지역별·과목별 학원 정보를 한곳에서. 동네 이름으로 우리 아이에게 맞는 학원을 찾아보세요.</p></div>
<div class="sec"><h2>지역으로 찾기</h2><p style="color:var(--sub);font-size:14px">동네를 선택하면 해당 지역의 과목별·학년별 학원 정보를 볼 수 있습니다.</p></div>
<div class="grid">${grid}</div>
<div class="note">본 사이트는 학원 정보를 지역·과목별로 안내합니다. 정확한 수업 시간 및 교습비는 각 학원에 방문상담을 통해 확인하시기 바랍니다.</div>`;
  return layout({title:`${SITE_NAME} | 전국 지역별·과목별 학원 정보`, desc:"전국 지역별·과목별 학원 정보를 한곳에서. 동네 이름으로 우리 아이에게 맞는 영어·수학·국어·과학·사회 학원을 찾아보세요.", canonical, jsonld:"", body});
}

// ---------- 지역 인덱스 ----------
function pageRegionIndex(){
  const idx = buildIndex();
  const bySgg = {};
  Object.values(idx.dongList).forEach(d=>{ (bySgg[d.sgg]=bySgg[d.sgg]||[]).push(d.dong); });
  const blocks = Object.keys(bySgg).sort().map(sgg=>{
    const ds=[...new Set(bySgg[sgg])].sort().map(d=>`<a class="chip" href="/${enc(d)}">${esc(d)}</a>`).join("");
    return `<div class="sec"><h2>${esc(sgg)}</h2><div class="chips">${ds}</div></div>`;
  }).join("");
  return layout({title:`지역별 학원 정보 | ${SITE_NAME}`, desc:"전국 지역별 학원 정보 목록. 시·군·구별 동네 학원 정보를 확인하세요.", canonical:`${SITE_URL}/지역`, jsonld:"", body:`<div class="bc"><a href="/">홈</a> › 지역별</div><h1>지역별 학원 정보</h1><p class="lead">전국 시·군·구별 동네 학원 정보입니다.</p>${blocks}`});
}

// ---------- 과목 인덱스 ----------
function pageSubjectIndex(){
  const body = `<div class="bc"><a href="/">홈</a> › 과목별</div><h1>과목별 학원 정보</h1>
<p class="lead">과목별 학원 정보를 안내합니다. 먼저 지역을 선택한 뒤 과목·학년을 골라 보세요.</p>
<div class="chips">${SUBJECTS.map(s=>`<span class="chip">${esc(s)}</span>`).join("")}</div>
<div class="sec"><p style="color:var(--sub)">지역을 먼저 선택하시면 해당 동네의 과목별·학년별 학원 정보를 보실 수 있습니다.</p></div>
<div class="sec"><a class="chip" href="/지역">지역별로 찾기 →</a></div>`;
  return layout({title:`과목별 학원 정보 | ${SITE_NAME}`, desc:"영어·수학·국어·과학·사회 과목별 학원 정보 안내.", canonical:`${SITE_URL}/과목`, jsonld:"", body});
}

// ---------- sitemap ----------
function sitemap(){
  const idx = buildIndex();
  const urls = [`${SITE_URL}/`, `${SITE_URL}/지역`, `${SITE_URL}/과목`];
  Object.keys(idx.byDong).forEach(d=>urls.push(`${SITE_URL}/${enc(d)}`));
  Object.keys(idx.pages).forEach(k=>{ const [d,s,l]=k.split("|"); urls.push(`${SITE_URL}/${enc(d)}-${enc(l)}${enc(s)}학원`); });
  CENTERS.forEach(c=>urls.push(`${SITE_URL}/center/${c.id}`));
  const body = `<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n${urls.map(u=>`<url><loc>${u}</loc></url>`).join("\n")}\n</urlset>`;
  return new Response(body, {headers:{"content-type":"application/xml; charset=utf-8"}});
}

function robots(){
  return new Response(`User-agent: *\nAllow: /\nSitemap: ${SITE_URL}/sitemap.xml\n`, {headers:{"content-type":"text/plain"}});
}

function notFound(){
  return new Response(layout({title:`페이지를 찾을 수 없습니다 | ${SITE_NAME}`, desc:"", canonical:SITE_URL+"/", jsonld:"", body:`<h1>페이지를 찾을 수 없습니다</h1><p class="lead">요청하신 페이지가 없습니다. <a href="/" style="color:var(--accent)">홈으로 돌아가기</a></p>`}), {status:404, headers:{"content-type":"text/html; charset=utf-8"}});
}

function html(s){ return new Response(s, {headers:{"content-type":"text/html; charset=utf-8","cache-control":"public, max-age=3600"}}); }

// ---------- 라우터 ----------
async function handle(request){
  const url = new URL(request.url);
  let path = decodeURIComponent(url.pathname);
  if(path==="/"||path==="") return html(pageHome());
  if(path==="/robots.txt") return robots();
  if(path==="/sitemap.xml") return sitemap();
  if(path==="/지역") return html(pageRegionIndex());
  if(path==="/과목") return html(pageSubjectIndex());

  const idx = buildIndex();

  // /center/:id
  let m = path.match(/^\/center\/(\d+)$/);
  if(m){ const c = CENTERS.find(x=>x.id===parseInt(m[1])); return c?html(pageCenter(c)):notFound(); }

  // /동-대상과목학원  (예: /덕풍동-중등영어학원)
  m = path.match(/^\/([가-힣0-9]+동)-(초등|중등|고등)(국어|영어|수학|과학|사회)학원$/);
  if(m){
    const [_, dong, lv, subj] = m;
    const key = `${dong}|${subj}|${lv}`;
    const chere = idx.pages[key];
    if(chere) return html(pageSubject(dong, subj, lv, chere));
    return notFound();
  }

  // /동  (예: /덕풍동)
  m = path.match(/^\/([가-힣0-9]+동)$/);
  if(m){ const chere = idx.byDong[m[1]]; return chere?html(pageDong(m[1], chere)):notFound(); }

  return notFound();
}

export default {
  async fetch(request){ try{ return await handle(request); }catch(e){ return new Response("Error: "+e.message+"\n"+e.stack, {status:500}); } }
};
